var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"……강하군.","JPN":"……強いな。","ENG":"...You're strong.","TWN":"……你很強。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 이상해. 마치 시간을 끌고 있는 것 같은 느낌인데.","JPN":"だがおかしい。時間稼ぎをしているような気がする。","ENG":"But something doesn't feel right. It's as if you're biding your time.","TWN":"但是又很奇怪，感覺像是在拖延時間。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"어째서 우리 공격을 받아치기만 하는 거지?","JPN":"なぜ俺たちの攻撃を受け流してばかりいる？","ENG":"Why are you only blocking our attacks?","TWN":"為什麼你只是在擋我們的攻擊？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제법 눈썰미가 좋으시네요.","JPN":"いい観察力ですね。","ENG":"You have quite a keen eye.","TWN":"觀察力還真不錯呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"엘리시움 그림자들의 함선, 코러스는 악단의 연주를 확산시키도록 설계되었죠.","JPN":"エリシウムシャドウたちの艦船、コーラスは楽団の演奏を拡散させるように設計されています。","ENG":"The ship of the Elysium Shadows, Chorus, was designed to amplify the Orchestra's performance.","TWN":"這艘愛樂暗影的艦船Chorus，是為了擴散樂團的演奏而設計的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 저는 당신들이 오기 전에, 미리 공연 준비를 마쳐두었답니다.","JPN":"そして私はあなたたちが来る前に、公演の準備を済ませておきました。","ENG":"And just before you arrived, I finished the preparations for the performance.","TWN":"在你們來之前，我就已經提前準備好了演出。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"공연이라고?","JPN":"公演だと？","ENG":"Performance?","TWN":"演出？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"소리는 곧 파동.","JPN":"音はすなわち波動。","ENG":"Sounds are waves.","TWN":"聲音即是波動。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"철과 철이 부딪치는 금속음, 부스트 해머의 굉음, 스파크가 튀며 발생하는 폭발음…….","JPN":"鉄と鉄がぶつかる金属音、ブーストハンマーの轟音、スパークが伴う爆発音……","ENG":"The clang of metal against metal, the roar of the boost hammer, the explosion right after sparks fly...","TWN":"鋼鐵與鋼鐵碰撞的金屬聲，鐵鎚的轟鳴，火花四濺的爆炸……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 당신들의 비명과 광기어린 웃음 소리.","JPN":"そしてあなたたちの悲鳴と、狂気じみた笑い声。","ENG":"And your screams and maniacal laughter.","TWN":"還有你們的慘叫和瘋狂的笑聲。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳에서 연주되는 모든 파동이 잔류 침식파와 뒤섞여 외부로 확산되고 있다는 뜻이죠.","JPN":"ここで演奏されているすべての波動は、残留侵食波と入り混じり外へと拡散されているのです。","ENG":"All waves played here will get mixed with the residual Corruption rays and spread outward.","TWN":"這裡演奏的所有波動都與殘留的侵蝕波混合，向外擴散。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"코러스의 파동 확산 장치를 작동시켜 두었군.","JPN":"コーラスの波動拡散装置を稼働させておいたな。","ENG":"You've activated Chorus' wave amplifier.","TWN":"你啟動了Chorus的波動擴散裝置。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 그게 무슨 의미가 있지? 어차피 그 그림자들이 아니면 사용할 수 없을 텐데?","JPN":"だがそれに何の意味がある？　どうせあのシャドウじゃないと扱えないはずだ。","ENG":"But what meaning does that have? Can't only those Shadows use it?","TWN":"但那有什麼意義呢？反正除了那些暗影，誰也用不了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 곧 무대에서 퇴장할 당신들에게는 그다지 의미가 없을지도 모르겠지만.","JPN":"そうでしょうか？　まもなく舞台から退場するあなたたちにとっては、あまり意味のないことかもしれませんが……","ENG":"Well, to someone who is about to get off the stage, perhaps it is meaningless.","TWN":"確實，對與即將從舞台上退場的你們來說，可能是沒什麼意義了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저에게 이 막간의 공연은 무척 중요한 의미를 가진답니다.","JPN":"私にとってこのインターミッションはとても重要なんです。","ENG":"To me, the final act has significant meaning.","TWN":"對我來說，這場短暫的表演意義非凡。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"정전인가?","JPN":"停電か？","ENG":"A blackout?","TWN":"停電了嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"함선의 동력원이 완전히 끊어졌군요. 하지만 컨버터의 작동은 충분히 확인했어요.","JPN":"艦船の動力源が完全に切れましたね。でもコンバーターの作動は十分確認できました。","ENG":"The ship's power has been completely cut off. But I checked myself that the converter is still working.","TWN":"艦船的動力源完全斷了。不過，我已經確認了轉換器的運作。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다시 말해, 당신들의 코러스도 여기까지.","JPN":"つまり、あなたたちのコーラスもここまでです。","ENG":"In other words, your Chorus ends here.","TWN":"換句話說，你們的表演也到此為止了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 이만 무대에서 퇴장하시길.","JPN":"そろそろ舞台から退場してもらいましょう。","ENG":"Then, please leave the stage.","TWN":"那麼，請從舞台上退場吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"……역시나.","JPN":"……やはり。","ENG":"...Just as I thought.","TWN":"……果然。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"코러스에 남아 있는 엘리시움의 잔류 침식파를 미끼로 쓰면, 나타날 거라고 생각했어요.","JPN":"コーラスに残っているエリシウムの残留侵食波をエサにすれば、現れると思っていました。","ENG":"I knew she'd show up if I used Elysium's residual Corruption rays remaining on Chorus as bait.","TWN":"如果用留在Chorus內的愛樂殘留侵蝕波作為誘餌，我想她會出現的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"SS_SHADOW_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마침내 각본의 주연 배우가 그 모습을 드러냈군요.","JPN":"ついにこの脚本の主役が姿を現してくれましたね。","ENG":"Finally, our lead actress has arrived.","TWN":"終於，劇本的主角現身了。"},"stage":{"bg":"SS_SHADOW_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……모르스.","JPN":"……モールス。","ENG":"...Mors.","TWN":"……死神莫爾斯。"},"stage":{"bg":"SS_SHADOW_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};